import type {RefObject} from 'react'
import {downloadCanvas} from '../../utils'
import {type ChartDataset} from 'chart.js'

export const handleDownload = (uniqueId: string, chart: RefObject<any>, isDarkMode: boolean = false) => {
  // Resizes the canvas for a bigger screenshot
  ;(chart.current as any)!.resize(1366, 768)

  const chartNode = document.getElementById(uniqueId) as HTMLCanvasElement

  // Copy the current canvas in order to apply a custom background color
  const destinationCanvas = document.createElement('canvas')

  destinationCanvas.width = chartNode.width
  destinationCanvas.height = chartNode.height

  const destCtx: CanvasRenderingContext2D = destinationCanvas.getContext('2d')!

  //create a rectangle with the desired color
  destCtx.fillStyle = !isDarkMode ? '#EDF2F7' : '#2D3748'
  destCtx.fillRect(0, 0, chartNode.width, chartNode.height)

  //Draw the original canvas onto the destination canvas
  destCtx.drawImage(chartNode, 0, 0)

  sleep(0).then(_ => (chart.current as any)!.resize())

  downloadCanvas(destinationCanvas, 'Trend.jpg', 'image/jpeg')

  // Resizes tho its original size making sure the download is complete first
}


export const formatLabel = (target:string) =>
    target
        .split('-')
        .map(
            (word: string) => word[0]?.toUpperCase() + word.substring(1).toLowerCase()
        )
        .join(' ');

export const labelsWithValue = (data:ChartDataset<any, number[]>[]) => {
    return data.map((d, index) => `${d.label} ${d.data[index]}`)
}

export const sleep = (ms: number) =>
    new Promise((resolve) => setTimeout(resolve, ms));
